// Confidence: AI classifier + LLM judge. Zero heuristics.

const inputItem = $input.first().json;

// 1. Classifier confidence
let classifierConf = 0.5;
try {
  const enrich = $('Enrich with Classification').first().json;
  classifierConf = parseFloat(enrich.classificationConfidence) || 0.5;
} catch(e) {}

// 2. LLM Judge score (parses JSON output via Structured Output Parser)
let judgeScore = null;
try {
  const judgeData = $('LLM Answer Judge').first().json;
  if (judgeData.score !== undefined) {
    judgeScore = parseFloat(judgeData.score);
  } else if (judgeData.text) {
    const parsed = JSON.parse(judgeData.text);
    judgeScore = parseFloat(parsed.score);
  }
  if (judgeScore !== null && !isNaN(judgeScore)) {
    judgeScore = Math.min(Math.max(judgeScore, 0), 1);
  }
} catch(e) {}

// Combined: judge weighted higher
const confidenceScore = (judgeScore !== null && !isNaN(judgeScore))
  ? classifierConf * 0.3 + judgeScore * 0.7
  : classifierConf;

const agentOutput = inputItem.output || "";
const sourceCount = (agentOutput.match(/источник:|source:/gi) || []).length;

return [{
  json: {
    ...inputItem,
    confidenceScore: Math.min(Math.max(confidenceScore, 0), 1),
    documentCount: sourceCount
  }
}];

// Template Response — applies rigid category templates per spec.
// "LLM для поиска и ответов, шаблоны - через код с заполнением полей"
// Confidence from: AI classifier + LLM Answer Judge. Zero heuristics.

const inputItem = $input.first().json;
const category = inputItem.classificationCategory || 'General';
const sessionId = inputItem.sessionId || '';
const agentOutput = inputItem.output || '';

// ---- Confidence: AI classifier + LLM judge ----
const classifierConf = parseFloat(inputItem.classificationConfidence) || 0.5;

let judgeScore = null;
try {
  const judgeData = $('LLM Answer Judge').first().json;
  const judgeText = judgeData.text || judgeData.output || '';
  const m = judgeText.match(/([0-9.]+)/);
  if (m) {
    judgeScore = parseFloat(m[1]);
    if (judgeScore > 1) judgeScore = judgeScore / 100; // normalize percentage
    judgeScore = Math.min(Math.max(judgeScore, 0), 1);
  }
} catch(e) { /* judge data unavailable */ }

const confidenceScore = (judgeScore !== null && !isNaN(judgeScore))
  ? classifierConf * 0.3 + judgeScore * 0.7   // weigh independent judge more
  : classifierConf;

const confidencePct = (Math.min(Math.max(confidenceScore, 0), 1) * 100).toFixed(0);
const now = new Date().toLocaleString('ru-RU', { timeZone: 'Europe/Moscow' });

const sourceMatches = agentOutput.match(/источник:|source:/gi);
const sourceCount = sourceMatches ? sourceMatches.length : 0;

// ---- Low confidence (below 60%) ----
if (confidenceScore < 0.6) {
  const catLabel = category === 'HR' ? 'Кадровый вопрос' :
                   category === 'Legal' ? 'Юридический вопрос' : 'Общий вопрос';

  return [{
    json: {
      output: (
        '## ⚠️ Ответ с пониженной уверенностью\n\n' +
        `**Категория:** ${catLabel}\n` +
        `**Уверенность:** ${confidencePct}% (ниже порога 60%)\n` +
        `**Найдено источников:** ${sourceCount}\n\n` +
        '---\n\n' +
        `${agentOutput}\n\n` +
        '---\n\n' +
        '⚠️ *Точность данного ответа ниже установленного порога. Рекомендуется проверка специалистом.*\n' +
        '📅 ' + now
      ),
      sessionId
    }
  }];
}

// ---- High confidence: category-specific rigid templates ----
const templates = {
  HR: {
    heading: '## 🏢 Ответ HR-ассистента\n\n**Категория:** Кадровый вопрос',
    disclaimer: '*Ответ основан на внутренних HR-документах и политиках компании. Источники документов имеют приоритет над формулировками ИИ-ассистента.*'
  },
  Legal: {
    heading: '## ⚖️ Ответ Юридического ассистента\n\n**Категория:** Юридический вопрос',
    disclaimer: '⚠️ *Данный ответ носит информационный характер. Нормативные документы и источники имеют приоритет над формулировками ИИ-ассистента. Для подготовки финальных юридических документов требуется проверка квалифицированным специалистом.*'
  },
  General: {
    heading: '## 📋 Ответ Ассистента\n\n**Категория:** Общий вопрос',
    disclaimer: '*Ответ основан на доступных документах базы знаний. Первоисточники имеют приоритет над формулировками ИИ-ассистента.*'
  }
};

const t = templates[category] || templates.General;

return [{
  json: {
    output: (
      `${t.heading}\n` +
      `**Уверенность:** ${confidencePct}%\n` +
      `**Найдено источников:** ${sourceCount}\n\n` +
      '---\n\n' +
      `${agentOutput}\n\n` +
      '---\n\n' +
      `${t.disclaimer}\n` +
      '📅 ' + now
    ),
    sessionId
  }
}];
